INSERT INTO `mybb_sg_sg_npcs` (`codigo`, `nombre`, `clan_grupo`, `cargo`, `frase`, `edad`, `descripcion`, `rango`, `nivel`) VALUES
('akihiro-sarutobi', 'Akihiro Sarutobi', 'Sarutobi - Hokage', 'Líder del Clan Sarutobi – Primer Hokage', '“El fuego puede destruir, pero también puede iluminar. Nuestro deber no es quemar el mundo, sino guiarlo en la oscuridad.”', '52', 'Akihiro Sarutobi es el actual líder del clan Sarutobi y uno de los hombres más respetados dentro de Konoha. Heredero del linaje fundador de la aldea, ha dedicado su vida a preservar la filosofía del equilibrio entre el hombre y la naturaleza, principio que define la identidad histórica de su clan. Su liderazgo se caracteriza por la prudencia, la disciplina y una profunda fe en las tradiciones que dieron origen a la aldea. Desde joven, Akihiro fue educado bajo los principios de control y responsabilidad en el uso del fuego. Aprendió que el poder no debía emplearse como instrumento de destrucción, sino como símbolo de guía y purificación. Su inteligencia estratégica y su capacidad para mantener la calma en situaciones críticas lo convirtieron en mediador natural en conflictos internos entre clanes. Sin embargo, la crisis actual del mundo ha puesto a prueba su convicción. Mientras otras aldeas consideran liberar los sellos del chakra, Akihiro sostiene que romperlos podría desatar una catástrofe irreversible. Esta postura lo ha colocado en el centro de un debate político y moral que amenaza con dividir a los líderes de Konoha. Hoy, Akihiro enfrenta la decisión más difícil de su vida: proteger el legado del pasado o aceptar el riesgo de un cambio necesario para salvar el futuro. Muchos lo ven como el último guardián del equilibrio, pero incluso él comienza a cuestionar si la tradición puede resistir el peso del tiempo.', 'Kage', 20),
('shinodera-nara', 'Shinodera Nara', 'Nara', 'Líder del Clan Nara – Consejero del Hokage', '“La verdadera victoria no se encuentra en la batalla ganada, sino en la guerra no luchada.”', '47', 'Shinodera Nara es el estratega principal de Konoha y líder del clan Nara, reconocido por su mente brillante y su capacidad para analizar escenarios complejos con rapidez. Desde su juventud demostró un talento excepcional para la planificación táctica, lo que lo llevó a convertirse en consejero directo del Hokage en asuntos militares y políticos. A pesar de su reputación como líder ejemplar, Shinodera carga con una debilidad personal que pocos conocen: su adicción al alcohol, desarrollada durante los años de guerra. Esta dependencia es un recordatorio constante del estrés y la responsabilidad que ha soportado a lo largo de su carrera. Aunque mantiene su compostura en público, su vida privada refleja el costo emocional del liderazgo. Su estilo de mando es pragmático y calculador. Prefiere evitar conflictos abiertos y buscar soluciones estratégicas que minimicen las pérdidas humanas. Gracias a su visión, el clan Nara se ha consolidado como el cerebro táctico de la aldea, responsable de planificar defensas, misiones y alianzas diplomáticas. Sin embargo, el desgaste físico y mental empieza a hacerse evidente. Shinodera sabe que el futuro de Konoha dependerá de decisiones que podrían definir el destino del mundo, y teme que un solo error estratégico pueda desencadenar una guerra que nadie podrá controlar.', 'Tokubetsu Jounin', 14),
('shiori-uchiha', 'Shiori Uchiha', 'Uchiha', 'Líder del Clan Uchiha – Capitán de las Fuerzas Armadas Konoha', '“El poder viene del dolor. Si no podemos cargar con el sufrimiento de nuestro pasado, ¿cómo enfrentaremos el futuro?”', '34', 'Shiori Uchiha es la actual líder del clan Uchiha y una figura marcada por el peso de la historia de su familia. Nacida en una época de tensión política, creció escuchando relatos sobre los sacrificios y tragedias que definieron el destino de su clan. Esta herencia la convirtió en una líder disciplinada y determinada. Como comandante, Shiori mantiene una política estricta contra el abuso del poder. Su principal objetivo es evitar que los errores del pasado se repitan, especialmente aquellos relacionados con el uso irresponsable del Sharingan. Bajo su liderazgo, el clan ha adoptado normas severas para regular el entrenamiento y el uso de sus habilidades. Su mente analítica y su capacidad para anticipar movimientos enemigos la han convertido en una pieza clave en la defensa de Konoha. Muchos consideran que su liderazgo representa una nueva era para los Uchiha, basada en la responsabilidad y el autocontrol en lugar de la ambición. No obstante, el uso constante de sus habilidades ha dejado secuelas físicas. Su visión en el ojo izquierdo se ha deteriorado con el tiempo, obligándola a depender más de su inteligencia que de su poder. Esta limitación es un recordatorio permanente del precio que conlleva el liderazgo.', 'Equivalente a ANBU', 15),
('miyako-senju', 'Miyako Senju', 'Senju', 'Líder del Clan Senju', '“La verdadera fuerza no está en dominar la naturaleza, sino en protegerla.”', '41', 'Miyako Senju es la actual líder del clan Senju y una de las figuras más influyentes en la política ambiental de Konoha. Descendiente de generaciones que aprendieron a respetar el poder de la naturaleza, ha dedicado su vida a restaurar el equilibrio entre la aldea y su entorno natural. Su dominio del Mokuton le ha permitido liderar proyectos de reconstrucción ecológica en los territorios cercanos a Konoha. Bajo su dirección, se han creado reservas forestales y sistemas de defensa natural que fortalecen la seguridad de la aldea sin recurrir a la destrucción del entorno. Miyako es conocida por su enfoque diplomático y su capacidad para mediar conflictos entre clanes. Su liderazgo ha fomentado la cooperación entre familias históricamente rivales, consolidando una cultura de unidad y respeto mutuo dentro de la aldea. Sin embargo, su rechazo a la guerra ha generado críticas entre sectores más agresivos de la sociedad. Algunos líderes consideran que su postura pacifista podría ser peligrosa en tiempos de crisis, especialmente si Konoha se ve obligada a enfrentarse a enemigos externos.', 'Jounin', 13),
('hayato-aburame', 'Hayato Aburame', 'Aburame', 'Líder del Clan Aburame – Jefe del Centro de Investigación', '“La verdadera fuerza no reside solo en el control, sino en la armonía entre el hombre y la naturaleza.”', '29', 'Hayato Aburame es el líder más joven entre los grandes clanes de Konoha, pero también uno de los más prometedores. Desde temprana edad demostró una afinidad excepcional con los insectos, desarrollando habilidades avanzadas de control y comunicación que lo destacaron dentro de su clan. Su liderazgo se caracteriza por la calma y la introspección. En lugar de imponer autoridad mediante la fuerza, Hayato busca comprender las emociones y necesidades de su gente. Esta actitud ha permitido sanar conflictos internos que habían persistido durante generaciones. Bajo su mando, los Aburame han reforzado su rol como expertos en espionaje e inteligencia. Sus habilidades para infiltrarse y recolectar información los convierten en un recurso invaluable para la defensa de Konoha y la vigilancia de amenazas externas. A pesar de su éxito, algunos miembros veteranos del clan dudan de su juventud y experiencia. Hayato es consciente de estas críticas y trabaja constantemente para demostrar que el liderazgo no depende de la edad, sino de la sabiduría.', 'Jounin', 12),
('hana-inuzuka', 'Hana Inuzuka', 'Inuzuka', 'Líder del Clan Inuzuka', '“La lealtad no se aprende, se vive.”', '27', 'Hana Inuzuka es la líder del clan Inuzuka y una de las figuras más carismáticas de la aldea. Su vínculo con los animales, especialmente con los perros ninja, ha sido fundamental para mantener la seguridad en las fronteras de Konoha y detectar amenazas antes de que se conviertan en peligro real. Desde pequeña, Hana mostró un talento natural para comunicarse con los animales. Esta habilidad le permitió desarrollar técnicas de rastreo y vigilancia que han salvado innumerables vidas. Su estilo de liderazgo combina valentía, intuición y un profundo sentido de responsabilidad hacia su clan. Hana es conocida por su compasión y su capacidad para inspirar confianza en los demás. Bajo su dirección, el clan Inuzuka ha fortalecido su rol como guardianes de las fronteras y protectores de los habitantes de la aldea. Sin embargo, su naturaleza impulsiva puede llevarla a tomar decisiones arriesgadas en situaciones críticas. Aunque su instinto suele ser correcto, algunos consejeros temen que su determinación la lleve a enfrentarse a amenazas que superen sus capacidades.', 'Jounin', 12),
('daichi-akimichi', 'Daichi Akimichi', 'Akimichi', 'Líder del Clan Akimichi', '“La fuerza no se mide por el tamaño del cuerpo, sino por la grandeza del corazón.”', '45', 'Daichi Akimichi es el actual líder del clan Akimichi y uno de los pilares logísticos más importantes de Konoha. Su familia ha sido históricamente responsable del suministro de alimentos y recursos esenciales, especialmente durante épocas de crisis, cuando la escasez amenazaba la supervivencia de la aldea. Daichi ha heredado esta responsabilidad con orgullo y determinación. Desde joven, demostró una resistencia física extraordinaria y una capacidad única para coordinar grandes operaciones de almacenamiento y distribución. Su liderazgo se caracteriza por la organización meticulosa y la capacidad de mantener la moral alta incluso en tiempos difíciles. Para él, la verdadera batalla no siempre ocurre en el campo de guerra, sino en la lucha por mantener a la comunidad unida y alimentada. Durante los años recientes, Daichi ha impulsado el desarrollo de nuevas técnicas agrícolas y sistemas de reserva estratégica de alimentos. Estas medidas han permitido que Konoha mantenga su autosuficiencia incluso cuando el comercio con otras aldeas se vuelve inestable o peligroso. Sin embargo, el peso de su responsabilidad lo mantiene en constante tensión. Daichi sabe que una sola mala cosecha o un bloqueo en las rutas de suministro podría desencadenar una crisis social. Por ello, vive preparado para escenarios extremos, siempre pensando en el bienestar colectivo antes que en su propia comodidad.', 'Equivalente a Jounin', 12),
('asuka-yamanaka', 'Asuka Yamanaka', 'Yamanaka', 'Líder del Clan Yamanaka – Segundo a Mando en el Centro de Investigación', '“Lo valioso de la mente no radica en dominarla, sino en comprenderla.”', '59', 'Asuka Yamanaka es el líder actual del clan Yamanaka y uno de los ninjas más sabios de Konoha. Su dominio de las técnicas mentales y la comunicación telepática lo ha convertido en una figura esencial para la coordinación estratégica de la aldea y la gestión de información sensible. Durante décadas, Asuka ha servido como asesor del Hokage en situaciones de crisis, proporcionando análisis psicológicos de enemigos y aliados por igual. Su habilidad para leer pensamientos y emociones le permite anticipar conflictos antes de que ocurran, lo que ha evitado innumerables enfrentamientos innecesarios. A pesar de su avanzada edad, Asuka mantiene una mente aguda y disciplinada. Bajo su liderazgo, el clan Yamanaka ha evolucionado más allá del espionaje tradicional, convirtiéndose en guardianes de la inteligencia estratégica de la aldea. Han desarrollado sistemas de comunicación mental que permiten coordinar operaciones militares en tiempo real. Sin embargo, su cuerpo ya no responde con la misma rapidez que en su juventud. Esta limitación física lo obliga a depender cada vez más de sus discípulos, lo que lo ha llevado a prepararse para la inevitable transición de liderazgo dentro de su clan.', 'Tokubetsu Jounin', 14),
('renshiro-hyuga', 'Renshiro Hyuga', 'Hyuga', 'Líder del Clan Hyuga', '“Verlo todo no es un privilegio, es una responsabilidad.”', '50', 'Renshiro Hyuga es el líder del clan Hyuga y el guardián principal de la vigilancia externa de Konoha. Gracias al poder del Byakugan, su clan ha sido responsable durante generaciones de observar y proteger las fronteras de la aldea, detectando amenazas antes de que se acerquen demasiado. Desde su juventud, Renshiro fue entrenado en disciplina extrema y autocontrol emocional. Su dominio del combate y su precisión estratégica lo convirtieron rápidamente en uno de los guerreros más respetados de su generación. Como líder, exige excelencia absoluta a sus subordinados, convencido de que la seguridad de la aldea depende de la perfección en cada movimiento. Su liderazgo ha fortalecido la reputación del clan Hyuga como defensores incansables de Konoha. Bajo su mando, se han establecido nuevas rutas de vigilancia y protocolos de respuesta rápida que han reducido significativamente los riesgos de infiltración enemiga. No obstante, su estricta visión del deber lo ha aislado emocionalmente. Renshiro cree que el sacrificio personal es el precio inevitable del liderazgo, y rara vez permite que otros vean sus dudas o temores, incluso cuando las decisiones que debe tomar ponen en riesgo a su propio clan.', 'Tokubetsu Jounin', 14);
INSERT INTO `mybb_sg_sg_npcs` (`codigo`, `nombre`, `clan_grupo`, `cargo`, `frase`, `edad`, `descripcion`, `rango`, `nivel`) VALUES
('renji-sarutobi', 'Renji Sarutobi', 'Sarutobi', 'Instructor de Combate de la Academia', '', '38', 'Renji es un instructor exigente y disciplinado que cree firmemente en la preparación constante. Participó en varias misiones de alto riesgo durante su juventud, lo que moldeó su estilo de enseñanza riguroso. Es respetado por sus alumnos, aunque muchos lo consideran severo. Su mayor temor es perder a uno de sus estudiantes en combate.', 'Chunnin', 11),
('kaede-nara', 'Kaede Nara', 'Nara', 'Analista Táctica Militar', '', '29', 'Kaede es una estratega brillante conocida por su capacidad para anticipar movimientos enemigos. Su mente lógica y su enfoque meticuloso la convierten en una pieza clave en la planificación de misiones. Trabaja largas horas analizando escenarios complejos y rara vez comete errores. La presión por la perfección es su mayor carga.', 'Equivalente a Chunnin', 10),
('takeru-uchiha', 'Takeru Uchiha', 'Uchiha', 'Capitán de Guardia Interna', '', '33', 'Takeru lidera una unidad encargada de la seguridad dentro de la aldea. Es disciplinado, observador y profundamente leal a Konoha. Cree que el poder debe utilizarse para prevenir conflictos antes de que comiencen. Su sentido del deber lo obliga a tomar decisiones difíciles que a menudo afectan su vida personal.', 'Jounin', 12),
('harumi-senju', 'Harumi Senju', 'Senju', 'Ingeniera de Barreras y Murallas', '', '35', 'Harumi es responsable del mantenimiento de las defensas físicas de la aldea. Su dominio del Mokuton le permite reparar estructuras y reforzar murallas rápidamente. Es trabajadora incansable y se toma su labor con absoluta seriedad. Considera que una defensa sólida es tan importante como un ejército fuerte.', 'Equivalente a Chunnin', 11),
('kaito-aburame', 'Kaito Aburame', 'Aburame', 'Espía de Inteligencia', '', '26', 'Kaito es un especialista en infiltración que utiliza insectos para observar a sus enemigos sin ser detectado. Habla poco y mantiene una actitud reservada, lo que lo hace difícil de leer. Su paciencia y discreción lo han convertido en uno de los agentes más efectivos de la aldea. Vive en constante alerta.', 'Chunnin', 10),
('sora-inuzuka', 'Sora Inuzuka', 'Inuzuka', 'Rastreadora de Fronteras', '', '24', 'Sora es una rastreadora rápida y enérgica que patrulla los límites de la aldea junto a su compañero canino. Su olfato y su resistencia física le permiten detectar intrusos a grandes distancias. Disfruta la emoción de la persecución y el trabajo en equipo. Su impulsividad es su mayor debilidad.', 'Chunnin', 7),
('daisuke-akimichi', 'Daisuke Akimichi', 'Akimichi', 'Supervisor de Almacenes', '', '41', 'Daisuke administra los depósitos de alimentos y recursos de Konoha. Su trabajo es esencial para garantizar la supervivencia de la aldea en tiempos de crisis. Es organizado y responsable, con una gran capacidad para planificar reservas estratégicas. El miedo a una escasez lo mantiene en constante vigilancia.', 'Equivalente a Chunnin', 8),
('mei-yamanaka', 'Mei Yamanaka', 'Yamanaka', 'Operadora de Comunicaciones Mentales', '', '31', 'Mei conecta mentalmente a escuadrones durante misiones, permitiendo coordinación instantánea. Es empática y mantiene la calma en situaciones caóticas. Su habilidad ha salvado vidas en múltiples operaciones. El uso constante de su poder la deja agotada emocionalmente.', 'Chunnin', 9),
('kenji-hyuga', 'Kenji Hyuga', 'Hyuga', 'Vigía de Torre Perimetral', '', '36', 'Kenji pasa largas horas observando el horizonte desde las torres de vigilancia. Su Byakugan le permite detectar movimientos sospechosos a grandes distancias. Es disciplinado y paciente, aunque su trabajo puede resultar solitario. Cree que la vigilancia constante es la primera línea de defensa.', 'Chunnin', 8),
('riku-tanabe', 'Riku Tanabe', 'Civil', 'Mensajero Oficial', '', '22', 'Riku es un joven veloz encargado de transportar mensajes urgentes entre sectores de la aldea. Aunque no pertenece a un clan ninja, su trabajo es esencial para la comunicación interna. Sueña con convertirse en un ninja reconocido algún día. Su determinación lo impulsa a asumir riesgos innecesarios.', 'Equivalente a Gennin', 3),
('akane-senju', 'Akane Senju', 'Senju', 'Sanadora de Campo', '', '32', 'Akane acompaña a escuadrones en misiones peligrosas para tratar heridas y estabilizar combatientes. Es compasiva y extremadamente competente bajo presión. Cree que salvar vidas es el verdadero propósito de un ninja. Las pérdidas que ha presenciado la han marcado profundamente.', 'Chunnin', 10),
('ryohei-uchiha', 'Ryohei Uchiha', 'Uchiha', 'Investigador de Incidentes', '', '40', 'Ryohei analiza sabotajes y actividades sospechosas dentro de la aldea. Su mente analítica y su atención al detalle lo convierten en un investigador confiable. Desconfía de todo hasta encontrar pruebas concluyentes. Esta actitud ha afectado sus relaciones personales.', 'Chunnin', 10),
('takumi-inuzuka', 'Takumi Inuzuka', 'Inuzuka', 'Explorador de Terreno', '', '28', 'Takumi reconoce rutas antes de que los escuadrones se desplieguen en misiones. Su conocimiento del terreno lo convierte en un guía esencial en operaciones fuera de la aldea. Se siente más cómodo en la naturaleza que en la ciudad. La soledad es el precio de su trabajo.', 'Chunnin', 7),
('ren-aburame', 'Ren Aburame', 'Aburame', 'Archivista de Inteligencia', '', '37', 'Ren custodia registros secretos y documentos históricos relacionados con amenazas pasadas. Posee una memoria excepcional y una paciencia extraordinaria. Cree que comprender el pasado es clave para proteger el futuro. Vive rodeado de silencio y conocimiento.', 'Equivalente a Chunnin', 8),
('fumiko-nara', 'Fumiko Nara', 'Nara', 'Coordinadora de Recursos Estratégicos', '', '34', 'Fumiko supervisa la distribución de suministros y el movimiento de tropas en situaciones de emergencia. Su habilidad para organizar información la convierte en una figura indispensable en la logística militar. Es eficiente y directa en su trabajo. Su mayor preocupación es mantener el orden en tiempos de crisis.', 'Equivalente a Chunnin', 9),
('hiroto-sarutobi', 'Hiroto Sarutobi', 'Sarutobi', 'Oficial de Patrulla Nocturna', '', '42', 'Hiroto supervisa las patrullas nocturnas que recorren los distritos más vulnerables de la aldea. Es un veterano disciplinado que prefiere prevenir conflictos antes de que ocurran. Conoce cada callejón y cada ruta de escape en Konoha. Su mayor preocupación es detectar amenazas silenciosas que puedan infiltrarse en la oscuridad.', 'Chunnin', 10),
('naomi-yamanaka', 'Naomi Yamanaka', 'Yamanaka', 'Interrogadora de Inteligencia', '', '36', 'Naomi es especialista en técnicas mentales utilizadas para obtener información de prisioneros y sospechosos. Su enfoque es calculado y metódico, siempre buscando la verdad sin recurrir a la violencia innecesaria. Es respetada por su capacidad para mantener el control emocional en situaciones tensas. Sin embargo, la naturaleza de su trabajo la ha vuelto desconfiada de los demás.', 'Jounin', 12),
('masaru-akimichi', 'Masaru Akimichi', 'Akimichi', 'Cocinero Militar y Encargado de Raciones', '', '44', 'Masaru dirige la preparación de alimentos para escuadrones en campaña. Su conocimiento sobre nutrición y conservación de alimentos permite mantener a los soldados en condiciones óptimas durante misiones prolongadas. Es conocido por su carácter alegre y su capacidad para levantar el ánimo del grupo. Cree firmemente que una buena comida puede cambiar el resultado de una batalla.', 'Equivalente a Chunnin', 8),
('daigo-hyuga', 'Daigo Hyuga', 'Hyuga', 'Instructor de Combate Cuerpo a Cuerpo', '', '39', 'Daigo entrena a reclutas en técnicas de combate cercano utilizando el estilo tradicional de su clan. Es estricto, disciplinado y perfeccionista en cada movimiento. Considera que la precisión es más importante que la fuerza. Aunque su reputación es intimidante, sus alumnos reconocen su dedicación absoluta a su formación.', 'Chunnin', 11),
('reina-senju', 'Reina Senju', 'Senju', 'Botánica y Custodia de Jardines Medicinales', '', '28', 'Reina cultiva plantas medicinales utilizadas por los sanadores de la aldea. Su profundo conocimiento de la naturaleza la convierte en una experta en remedios y antídotos. Prefiere trabajar en silencio', 'Equivalente a Chunnin', 7);
